    (ores_utility_system_tenant_id_fn(), 'EQDTOUCH', 0, 'Equity Double Touch Option',
     'Equity Double Touch Option: a touch option with two barrier levels, paying out if the equity touches either barrier (double-one-touch) or paying out only if neither barrier is ever touched (double-no-touch) before expiry.',
     'equity', 'EquityDoubleTouchOption', 'NONE', 75, current_user, current_user, 'system.initial_load', 'Initial population of instrument codes'),
    (ores_utility_system_tenant_id_fn(), 'EQDIG', 0, 'Equity Digital Option',
