    (ores_utility_system_tenant_id_fn(), 'COMMWINBAR', 0, 'Commodity Window Barrier Option',
     'Commodity Window Barrier Option: a barrier option whose knock-in/knock-out condition is only monitored during a specified window of time within the option''s life (e.g. the final month before expiry), rather than continuously from trade date to expiry as in the standard Commodity Barrier Option.',
     'commodity', 'CommodityWindowBarrierOption', 'NONE', 111, current_user, current_user, 'system.initial_load', 'Initial population of instrument codes'),
    (ores_utility_system_tenant_id_fn(), 'COMMGENBAR', 0, 'Commodity Generic Barrier Option',
     'Commodity Generic Barrier Option: a flexible barrier-option trade type in ORE covering the general family of knock-in/knock-out structures (single or double barrier, continuous or discrete monitoring) via configurable schedule and event parameters, rather than the more narrowly-specified Commodity Barrier Option/Double Barrier Option/Window Barrier Option trade types.',
     'commodity', 'CommodityGenericBarrierOption', 'NONE', 112, current_user, current_user, 'system.initial_load', 'Initial population of instrument codes'),
    (ores_utility_system_tenant_id_fn(), 'COMMBSKT', 0, 'Commodity Basket Option',
     'Commodity Basket Option: an option whose payoff depends on a weighted basket of commodity prices rather than a single one, typically struck on the basket''s average or weighted-sum performance at expiry. Cheaper than a strip of options on each constituent individually because the basket''s volatility benefits from imperfect correlation between its members.',
     'commodity', 'CommodityBasketOption', 'NONE', 113, current_user, current_user, 'system.initial_load', 'Initial population of instrument codes'),
    (ores_utility_system_tenant_id_fn(), 'COMMRNBW', 0, 'Commodity Rainbow Option',
     'Commodity Rainbow Option: a multi-asset option whose payoff depends on the best- or worst-performing (or a ranked combination) of several commodity prices, rather than their combined basket value. Distinct from a Basket Option in that the payoff is driven by the relative ranking of the constituents, not their weighted sum.',
     'commodity', 'CommodityRainbowOption', 'NONE', 114, current_user, current_user, 'system.initial_load', 'Initial population of instrument codes'),
    (ores_utility_system_tenant_id_fn(), 'COMMRESET', 0, 'Commodity Strike Resettable Option',
     'Commodity Strike Resettable Option: an option whose strike is reset to (or relative to) the commodity price''s prevailing level on one or more specified reset dates during the option''s life, rather than being fixed at trade inception -- used to structure cliquet-like or ratchet payoffs that lock in favorable moves.',
     'commodity', 'CommodityStrikeResettableOption', 'NONE', 115, current_user, current_user, 'system.initial_load', 'Initial population of instrument codes')
